import React, { useState } from 'react';
import './MenuPrincipal.css';
import { 
  IconoInicio, 
  IconoUsuario, 
  IconoCampana, 
  IconoSalir,
  IconoMapa,
  IconoDolar,
  IconoCorazon,
  IconoRayo,
  IconoBuscar
} from '../../componentes/Iconos';

const MenuPrincipalEstudiante = ({ onLogout }) => {
  const [filtroActivo, setFiltroActivo] = useState('todo');
  const [paginaActual, setPaginaActual] = useState(1);
  const ofertasPorPagina = 12; // Para grid de 3x4

  // Generamos 15 ofertas de mock variadas
  const ofertasData = Array.from({ length: 15 }, (_, i) => ({
    id: i + 1,
    titulo: [
      "Desarrollador Frontend Junior", 
      "Analista de Datos", 
      "Practicante UI/UX", 
      "Backend Dev Node.js", 
      "QA Engineer", 
      "Project Manager Jr", 
      "Soporte Técnico", 
      "Marketing Digital", 
      "DevOps Trainee", 
      "Ciberseguridad Junior"
    ][i % 10],
    empresa: ["Tech Innovators", "Data Solutions", "Creative Studio", "Global Tech", "Fast Code"][i % 5],
    ubicacion: ["CDMX", "Monterrey", "Guadalajara", "Queretaro", "Remoto"][i % 5],
    modalidad: ["Tiempo Completo", "Híbrido", "Medio Tiempo"][i % 3],
    salario: `${(i + 10) * 1000} - ${(i + 15) * 1000} MXN`,
    match: i === 0 || i === 7 ? 95 : 70, // Simulamos 2 matches
    esRemoto: (i % 5) === 4
  }));

  // Lógica de filtrado
  const ofertasFiltradas = ofertasData.filter(oferta => {
    if (filtroActivo === 'todo') return true;
    if (filtroActivo === 'remoto') return oferta.esRemoto;
    if (filtroActivo === 'matches') return oferta.match >= 90;
    return true;
  });

  // Lógica de paginación
  const totalPaginas = Math.ceil(ofertasFiltradas.length / ofertasPorPagina);
  const indiceUltimoItem = paginaActual * ofertasPorPagina;
  const indicePrimerItem = indiceUltimoItem - ofertasPorPagina;
  const ofertasPaginadas = ofertasFiltradas.slice(indicePrimerItem, indiceUltimoItem);

  const cambiarPagina = (num) => {
    setPaginaActual(num);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="dashboard-container">
      <aside className="sidebar">
        <div className="sidebar-logo">
          <IconoRayo />
          <span>UniJob</span>
        </div>
        <nav className="sidebar-nav">
          <button className="nav-item active">
            <IconoInicio />
            <span>Inicio</span>
          </button>
          <button className="nav-item">
            <IconoUsuario />
            <span>Mi Perfil</span>
          </button>
        </nav>
        <button className="logout-btn" onClick={onLogout}>
          <IconoSalir />
          <span>Cerrar Sesión</span>
        </button>
      </aside>

      <main className="main-content">
        <header className="top-bar">
          <div className="search-container">
            <IconoBuscar />
            <input type="text" placeholder="Buscar empleo, empresa o habilidad..." />
          </div>
          <div className="top-bar-actions">
            <div className="user-profile-summary">
              <div className="user-info">
                <span className="user-name">Juan Pérez</span>
                <span className="user-carrera">Ing. en software</span>
              </div>
              <div className="user-avatar">JP</div>
            </div>
          </div>
        </header>

        <section className="feed-layout full-width">
          <div className="feed-main">
            <div className="feed-header">
              <h2>Ofertas para ti ({ofertasFiltradas.length})</h2>
              <div className="feed-filters">
                <button className={`filter-chip ${filtroActivo === 'todo' ? 'active' : ''}`} onClick={() => {setFiltroActivo('todo'); setPaginaActual(1);}}>Todo</button>
                <button className={`filter-chip ${filtroActivo === 'remoto' ? 'active' : ''}`} onClick={() => {setFiltroActivo('remoto'); setPaginaActual(1);}}>Remoto</button>
                <button className={`filter-chip ${filtroActivo === 'matches' ? 'active' : ''}`} onClick={() => {setFiltroActivo('matches'); setPaginaActual(1);}}>Matches</button>
              </div>
            </div>

            <div className="jobs-grid">
              {ofertasPaginadas.map(oferta => (
                <div key={oferta.id} className="job-card">
                  <div className="job-card-header">
                    <div className="company-logo-placeholder">{oferta.empresa[0]}</div>
                    <div className="job-info">
                      <h3>{oferta.titulo}</h3>
                      <span className="company-name">{oferta.empresa}</span>
                    </div>
                  </div>
                  <div className="job-details">
                    <div className="detail-item"><IconoMapa /><span>{oferta.ubicacion}</span></div>
                    <div className="detail-item"><IconoDolar /><span>{oferta.salario}</span></div>
                  </div>
                  <div className="job-card-footer">
                    {oferta.match >= 90 ? (
                      <div className="match-tag-simple">¡Match!</div>
                    ) : <div></div>}
                    <button className="apply-btn-small">Ver oferta</button>
                  </div>
                </div>
              ))}
            </div>

            {totalPaginas > 1 && (
              <div className="pagination">
                <button disabled={paginaActual === 1} onClick={() => cambiarPagina(paginaActual - 1)}>Anterior</button>
                {Array.from({ length: totalPaginas }, (_, i) => (
                  <button 
                    key={i + 1} 
                    className={paginaActual === i + 1 ? 'active' : ''} 
                    onClick={() => cambiarPagina(i + 1)}
                  >
                    {i + 1}
                  </button>
                ))}
                <button disabled={paginaActual === totalPaginas} onClick={() => cambiarPagina(paginaActual + 1)}>Siguiente</button>
                {paginaActual !== totalPaginas && <button onClick={() => cambiarPagina(totalPaginas)}>Última</button>}
              </div>
            )}
          </div>
        </section>
      </main>
    </div>
  );
};

export default MenuPrincipalEstudiante;
